      }
    },
    "earliest_divergence": {
      "type": "object"
    },
    "evidence_coverage": {
      "type": "object"
    },
    "analysis_quality": {
      "type": "object"
    },
    "incomplete_reason": {
      "type": "string",
      "minLength": 1
    },
    "suspected_locations": {
      "type": "array",
      "items": {}
    },
    "root_cause_hypothesis": {
      "type": "string",
      "minLength": 1
    },
    "verification_steps": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      }
    },
    "patch_direction": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      }
    },
    "needs_human_review": {
      "type": [
        "boolean",
        "null"
      ]
    },
    "scenario": {
      "type": "string",
      "minLength": 1
    },
    "quality_flags": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      }
    }
  },
  "additionalProperties": false,
  "$defs": {
    "ExpectationAttribution": {
      "$ref": "#/$defs/ExpectationAttribution"
    },
    "ChainNode": {
      "$ref": "#/$defs/ChainNode"
    }
  },
  "required": [
    "expectation_attributions",
    "causal_category",
    "root_cause_hypothesis"
  ]
}
```

### 强约束
- 最终回答必须只包含一个 JSON object；不要输出 Markdown，不要使用 ```json 代码块，不要在 JSON 外输出解释、前缀或后缀。
- 最终回答首字符必须是 `{`，末字符必须是 `}`。
- JSON 字符串内部如需引用用户原词，禁止直接写未转义英文双引号；请使用中文引号“”或转义为 `\"`。
- 必须包含 `required` 列表中的所有字段。
- 每个字段值必须匹配 schema 中的类型。
- 以下字段必须非空（空字符串/空数组/空对象/None 均视为不合规，会被阻断）：['causal_category', 'expectation_attributions', 'root_cause_hypothesis']
- `additionalProperties: false`：禁止输出 schema 未定义的字段。
- 禁止把 schema 里的类型描述符（如 "string"）原样当作内容填进去——每个字段必须填入真实内容。

```json
